SELECT COUNT(*)
FROM user_phone_bindings
WHERE phone = #{phone}

mapper.update:
-- 1. 将旧手机号设为已更换
UPDATE user_phone_bindings
SET is_active = 0,
    replace_time = NOW(),
    replace_reason = #{replaceReason},
    update_time = NOW()
WHERE user_id = #{userId}
  AND phone = #{oldPhone}
  AND is_active = 1;

-- 2. 如果新手机号不存在绑定记录，则创建新记录
INSERT IGNORE INTO user_phone_bindings (
    user_id, user_shard, phone, bind_type, bind_time,
    verify_code, verify_ip, is_active, create_time, update_time
) VALUES (
    #{userId}, #{userShard}, #{newPhone}, 'sms_login', NOW(),
    #{verifyCode}, #{verifyIp}, 1, NOW(), NOW()
);

-- 3. 确保新手机号为激活状态（如果记录已存在但未激活）
UPDATE user_phone_bindings
SET is_active = 1,
    verify_code = #{verifyCode},
    verify_ip = #{verifyIp},
    update_time = NOW()
WHERE user_id = #{userId}
  AND phone = #{newPhone}

UPDATE user_phone_bindings
SET is_active = 0,
    update_time = NOW()
WHERE user_id = #{userId}
  AND phone != #{excludePhone}
  AND is_active = 1
